u8 input_left = 0, input_right = 0, input_jump = 0, input_down = 0, input_shoot = 0, input_pause = 0, input_start = 0;

void input_update(void) {
    cpct_scanKeyboard();
    input_left  = (u8)(cpct_isKeyPressed(Key_CursorLeft)  || cpct_isKeyPressed(Key_A) || cpct_isKeyPressed(Joy0_Left));
    input_right = (u8)(cpct_isKeyPressed(Key_CursorRight) || cpct_isKeyPressed(Key_D) || cpct_isKeyPressed(Joy0_Right));
    input_jump  = (u8)(cpct_isKeyPressed(Key_CursorUp)    || cpct_isKeyPressed(Key_W) || cpct_isKeyPressed(Joy0_Up));
    input_down  = (u8)(cpct_isKeyPressed(Key_CursorDown)  || cpct_isKeyPressed(Key_S) || cpct_isKeyPressed(Joy0_Down));
    input_shoot = (u8)(cpct_isKeyPressed(Key_Space)       || cpct_isKeyPressed(Key_X) || cpct_isKeyPressed(Joy0_Fire1));
    input_pause = (u8)(cpct_isKeyPressed(Key_P));
    input_start = (u8)(cpct_isKeyPressed(Key_Return));
}

