    i16 top;
    i16 bottom;

    left = (i16)x;
    right = left + (i16)w - 1;
    top = (i16)y;
    bottom = top + (i16)h - 1;

    if (bottom >= (i16)gtilegroundy - 1) {
        return 1;
    }
    if (bottom >= (i16)gtileplatformy - 1 && bottom <= (i16)gtileplatformy + 2 && right >= 24 && left <= 56) {
        return 1;
    }
    return 0;
