void enemyspawn(Enemy* enemy, u8 x, u8 y, u8 kind, u8 move_right) {
    if (!enemy) {
        return;
    }

    enemy->x = x;
    enemy->y = y;
    enemy->vx = move_right ? 1 : -1;
    enemy->vy = 0;
    enemy->active = 1;
    enemy->kind = kind;

    if (kind == 1) {
        enemy->w = 5;
        enemy->h = 14;
        enemy->health = 2;
        enemy->reward = 180;
        enemy->vx = move_right ? 2 : -2;
    } else if (kind == 2) {
        enemy->w = 6;
        enemy->h = 10;
        enemy->health = 1;
        enemy->reward = 150;
        enemy->vy = move_right ? 1 : -1;
        enemy->vx = 1;
    } else if (kind == 3) {
        enemy->w = 10;
        enemy->h = 18;
        enemy->health = 8;
        enemy->reward = 800;
        enemy->vx = move_right ? 1 : -1;
    } else {
        enemy->w = 4;
        enemy->h = 16;
        enemy->health = 1;
        enemy->reward = 100;
    }
}

void enemyupdate(Enemy* enemy) {
    i16 nextx;
    i16 nexty;

    if (!enemy || !enemy->active) {
        return;
    }

    if (enemy->kind == 2) {
        nextx = (i16)enemy->x + (i16)enemy->vx;
        nexty = (i16)enemy->y + (i16)enemy->vy;

        if (nextx < 8 || nextx > 72) {
            enemy->vx = (i8)(-enemy->vx);
            nextx = (i16)enemy->x + (i16)enemy->vx;
        }
        if (nexty < 56 || nexty > 120) {
            enemy->vy = (i8)(-enemy->vy);
            nexty = (i16)enemy->y + (i16)enemy->vy;
        }

        enemy->x = (u8)nextx;
        enemy->y = (u8)nexty;
        return;
    }

    nextx = (i16)enemy->x + (i16)enemy->vx;
    if (nextx < 2) {
        nextx = 2;
        enemy->vx = 1;
    }
