u8 enemydamage(Enemy* enemy, u8 damage) {
    if (!enemy || !enemy->active) {
        return 0;
    }

    if (damage >= enemy->health) {
        enemy->health = 0;
        enemy->active = 0;
        return 1;
    }

    enemy->health = (u8)(enemy->health - damage);
    return 0;
}
