#include "entities/projectile.h"
#include <cpctelera.h>

Projectile projectile[PROJECTILE_MAX];

void projectile_init(void) {
    u8 i;
    for (i = 0; i < PROJECTILE_MAX; ++i) {
        projectile[i].active = 0;
    }
}

void projectile_erase_all(void) {
    u8 i;
    for (i = 0; i < PROJECTILE_MAX; ++i) {
        if (projectile[i].prev_active) {
            cpct_drawSolidBox(cpct_getScreenPtr(CPCT_VMEM_START, projectile[i].prev_x, projectile[i].prev_y), 0x00, projectile[i].prev_w, projectile[i].prev_h);
        }
    }
}

void projectile_store_prev_all(void) {
    u8 i;
    for (i = 0; i < PROJECTILE_MAX; ++i) {
        projectile[i].prev_x = projectile[i].x;
        projectile[i].prev_y = projectile[i].y;
        projectile[i].prev_w = projectile[i].w;
        projectile[i].prev_h = projectile[i].h;
        projectile[i].prev_active = projectile[i].active;
    }
}

void projectile_update(void) {
    u8 i;
    for (i = 0; i < PROJECTILE_MAX; ++i) {
        if (!projectile[i].active) continue;
        projectile[i].x += projectile[i].vx;
        projectile[i].y += projectile[i].vy;
        // Fuera de pantalla
        if (projectile[i].x > 160 || projectile[i].y > 200) {
            projectile[i].active = 0;
        }
    }
}

void projectile_render_all(void) {
    u8 i;
    for (i = 0; i < PROJECTILE_MAX; ++i) {
        if (!projectile[i].active) continue;
        // Sprite temporal: caja amarilla
        cpct_drawSolidBox(cpct_getScreenPtr(CPCT_VMEM_START, projectile[i].x, projectile[i].y), 0x3C, 8, 8);
    }
}

void projectile_spawn(u8 owner, u8 x, u8 y, u8 vx, u8 vy, u8 type) {
    u8 i;
    for (i = 0; i < PROJECTILE_MAX; ++i) {
        if (!projectile[i].active) {
            projectile[i].owner = owner;
            projectile[i].type = type;
            projectile[i].x = x;
            projectile[i].y = y;
            projectile[i].vx = vx;
            projectile[i].vy = vy;
            projectile[i].w = 8;
            projectile[i].h = 8;
            projectile[i].active = 1;
            break;
        }
    }
}
